import React, { useState } from 'react'
import { supabase } from '../../lib/supabaseClient'

export const Register: React.FC = () => {
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [username, setUsername] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError('')
    setSuccess('')
    const { error } = await supabase.auth.signUp({
      email, password,
      options: { data: { full_name: username } }
    })
    if (error) setError(error.message)
    else setSuccess('Account created! Check your email to confirm, then login.')
    setLoading(false)
  }

  return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', background:'#0a0a0a' }}>
      <div style={{ background:'#0d0d0d', border:'1px solid #c8a200', borderRadius:'16px', padding:'40px', maxWidth:'400px', width:'100%' }}>
        <div style={{ textAlign:'center', marginBottom:'30px' }}>
          <h1 style={{ color:'#FFD700', fontSize:'32px', fontWeight:'bold', margin:0 }}>TEAMSYNK</h1>
          <p style={{ color:'#666', marginTop:'8px' }}>Create your account</p>
        </div>

        {error && <div style={{ background:'#ff444433', color:'#ff4444', padding:'10px', borderRadius:'8px', marginBottom:'16px' }}>{error}</div>}
        {success && <div style={{ background:'#00ff4433', color:'#00cc33', padding:'10px', borderRadius:'8px', marginBottom:'16px' }}>{success}</div>}

        <form onSubmit={handleRegister}>
          <div style={{ marginBottom:'16px' }}>
            <label style={{ color:'#aaa', fontSize:'14px', display:'block', marginBottom:'6px' }}>Username</label>
            <input type="text" value={username} onChange={e => setUsername(e.target.value)} placeholder="GamerTag123" required
              style={{ width:'100%', padding:'12px', background:'#1a1a1a', border:'1px solid #333', borderRadius:'8px', color:'white', fontSize:'16px', boxSizing:'border-box' }} />
          </div>
          <div style={{ marginBottom:'16px' }}>
            <label style={{ color:'#aaa', fontSize:'14px', display:'block', marginBottom:'6px' }}>Email</label>
            <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="your@email.com" required
              style={{ width:'100%', padding:'12px', background:'#1a1a1a', border:'1px solid #333', borderRadius:'8px', color:'white', fontSize:'16px', boxSizing:'border-box' }} />
          </div>
          <div style={{ marginBottom:'24px' }}>
            <label style={{ color:'#aaa', fontSize:'14px', display:'block', marginBottom:'6px' }}>Password</label>
            <input type="password" value={password} onChange={e => setPassword(e.target.value)} placeholder="••••••••" required
              style={{ width:'100%', padding:'12px', background:'#1a1a1a', border:'1px solid #333', borderRadius:'8px', color:'white', fontSize:'16px', boxSizing:'border-box' }} />
          </div>
          <button type="submit" disabled={loading}
            style={{ width:'100%', padding:'14px', background:'linear-gradient(to right, #c8a200, #FFD700)', border:'none', borderRadius:'8px', color:'#0a0a0a', fontSize:'16px', fontWeight:'bold', cursor:'pointer' }}>
            {loading ? 'Creating account...' : 'Create Account'}
          </button>
        </form>

        <p style={{ textAlign:'center', color:'#666', marginTop:'20px' }}>
          Already have an account?{' '}
          <a href="/login" style={{ color:'#c8a200', textDecoration:'none' }}>Login here</a>
        </p>
      </div>
    </div>
  )
}
